        "3. Lemmatization: Reduce words to their base form using SpaCy.",
        "4. Named Entity Recognition (NER): Identify key entities (e.g., skills, companies, job titles) using SpaCy's NER.",
        "5. Custom Dictionary Augmentation: Enrich extracted keywords with synonyms and related terms from a domain-specific dictionary (e.g., technical skills, HR terms).",
        "6. TF-IDF Scoring: Calculate TF-IDF scores for each term in both the job description and resume sections.",
        "7. Keyword Selection: Select top N keywords based on TF-IDF scores and relevance (e.g., filtering out overly generic terms)."
      ]
    },
    "similarity_calculation": {
      "experience": {
        "method": "Cosine Similarity on Keyword Vectors",
        "description": "Calculate the cosine similarity between keyword vectors extracted from the 'experience' sections of the job description and resume.  Each experience entry is treated as a document.",
        "details": "Keywords are weighted by TF-IDF.  A minimum overlap threshold (e.g., 0.1) can be applied to avoid matching unrelated experiences.",
        "weight": 1.0
      },
      "skills": {
        "method": "Jaccard Similarity with Synonym Expansion",
        "description": "Calculate the Jaccard similarity (intersection over union) between skill sets listed in the job description and resume. Synonym expansion is performed using WordNet or a custom thesaurus.",
        "details": "Skills are normalized (e.g., 'Java' and 'Java Programming' are considered the same).  Skills are stemmed before comparison.",
        "weight": 1.0
      },
      "education": {
        "method": "String Similarity and Semantic Matching",
        "description": "Match education entries based on degree name, major, and institution. A combination of string similarity (Levenshtein distance) and semantic matching (using word embeddings) is used.",
        "details": "Higher weight is given to exact matches of degree names. Semantic matching is used to identify related majors (e.g., 'Computer Science' and 'Software Engineering').",
        "weight": 0.8
      },
      "certifications": {
        "method": "Exact and Fuzzy String Matching",
        "description": "Identify matching certifications using both exact and fuzzy string matching (e.g., using the FuzzyWuzzy library).",
        "details": "Partial matches (e.g., a slightly different certification name) receive a lower score.  Certifications from reputable organizations receive a higher weight.",
        "weight": 0.9
      },
      "projects": {
        "method": "Keyword Overlap and Description Similarity",
        "description": "Analyzes project descriptions in the resume for keyword overlap with the job description's required skills and responsibilities.  Cosine similarity is used to compare project descriptions.",
        "details": "Projects demonstrating relevant experience (e.g., AI projects for an AI role) are weighted higher.",
         "weight": 0.7
      }
    },
    "scoring": {
      "detailed": {
        "experience": "score_experience = similarity_experience * component_weights['experience']",
        "skills": "score_skills = similarity_skills * component_weights['skills']",
        "education": "score_education = similarity_education * component_weights['education']",
        "certifications": "score_certifications = similarity_certifications * component_weights['certifications']",
        "projects": "score_projects = similarity_projects * component_weights['projects']"
      },
      "aggregate": {
        "formula": "match_score = score_experience + score_skills + score_education + score_certifications + score_projects",
        "normalization": "match_score = min(1.0, match_score)  # Ensure match_score is between 0.0 and 1.0"
      }
    },
    "match_thresholds": {
      "excellent": 0.85,
      "good": 0.7,
